import axios from 'axios'
import { showToast } from '@/components/ToastMessage'
import router from '@/router'

// 创建 axios 实例
const request = axios.create({
  baseURL: process.env.VUE_APP_API_URL,
  timeout: 30000,
  headers: {
    'Content-Type': 'application/json',
    'Accept': 'application/json'
  },
  withCredentials: true
})

// 请求拦截器
request.interceptors.request.use(
  config => {
    const token = localStorage.getItem('access_token')
    if (token) {
      config.headers.Authorization = `Bearer ${token}`
    }

    // 如果是工作经历相关的请求，进行详细调试
    if (config.url.includes('/work-experiences/')) {
      const requestData = typeof config.data === 'string' ? JSON.parse(config.data) : config.data
      console.log('工作经历请求详情:', {
        url: config.url,
        method: config.method,
        rawData: config.data,
        parsedData: requestData,
        hasCompanyDescription: requestData && 'company_description' in requestData,
        allFields: requestData ? Object.keys(requestData) : [],
        prototype: requestData ? Object.getPrototypeOf(requestData) : null
      })
    }

    if (config.data && typeof config.data === 'object') {
      // 如果是工作经历请求，确保只包含允许的字段
      if (config.url.includes('/work-experiences/')) {
        const allowedFields = [
          'id', 'company', 'position', 'department',
          'start_date', 'end_date', 'is_current',
          'description', 'achievements', 'technologies'
        ]
        const data = { ...config.data }
        Object.keys(data).forEach(key => {
          if (!allowedFields.includes(key)) {
            console.warn(`删除非法字段: ${key}`)
            delete data[key]
          }
        })
        config.data = data
      }
      config.data = JSON.stringify(config.data)
    }

    return config
  },
  error => {
    return Promise.reject(error)
  }
)

// 响应拦截器
request.interceptors.response.use(
  response => {
    console.log('Response Success:', {
      status: response.status,
      data: response.data,
      headers: response.headers
    })
    return response
  },
  error => {
    console.error('Response Error Details:', {
      message: error.message,
      code: error.code,
      config: error.config,
      response: error.response ? {
        status: error.response.status,
        data: error.response.data,
        headers: error.response.headers,
        url: error.response.config.url
      } : 'No Response',
      request: error.request ? {
        url: error.request.url,
        method: error.request.method,
        headers: error.request.headers,
        data: error.config.data
      } : 'No Request'
    })

    if (error.code === 'ERR_NETWORK') {
      showToast('无法连接到服务器，请检查网络连接', 'error')
      return Promise.reject(new Error('网络连接失败'))
    }
    if (error.response?.status === 400) {
      showToast(error.response.data.message || '请求参数错误', 'error')
    } else if (error.response?.status === 401) {
      localStorage.removeItem('access_token')
      localStorage.removeItem('refresh_token')
      showToast('登录已过期，请重新登录', 'warning')
      router.push('/login')
    }
    return Promise.reject(error)
  }
)

export default request
